import { useState, useEffect } from 'react';
import { doctorAPI } from '../../utils/api';
import { useApp } from '../../context/AppContext';
import toast from 'react-hot-toast';

const STATUS_BADGE = {
  Pending: 'badge-pending', Approved: 'badge-approved',
  Completed: 'badge-completed', Cancelled: 'badge-cancelled', Rescheduled: 'badge-rescheduled'
};

export default function DoctorAppointments() {
  const { doctorId } = useApp();
  const [appointments, setAppointments] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState('all');
  const [treatmentModal, setTreatmentModal] = useState(null);
  const [treatmentText, setTreatmentText] = useState('');
  const [notes, setNotes] = useState('');

  useEffect(() => { if (doctorId) load(); }, [doctorId]);

  const load = async () => {
    setLoading(true);
    try {
      const res = await doctorAPI.getAppointments(doctorId);
      setAppointments(res.data);
    } catch { toast.error('Failed to load'); } finally { setLoading(false); }
  };

  const handleStatus = async (id, status) => {
    try {
      await doctorAPI.updateStatus(id, { status });
      toast.success(`Marked as ${status}`);
      load();
    } catch (err) { toast.error(err.response?.data?.error || 'Failed'); }
  };

  const openTreatment = (appt) => {
    setTreatmentModal(appt);
    setTreatmentText(appt.treatment_details || '');
    setNotes(appt.notes || '');
  };

  const saveTreatment = async () => {
    try {
      await doctorAPI.updateTreatment(treatmentModal.id, { treatment_details: treatmentText, notes });
      toast.success('Treatment details saved!');
      setTreatmentModal(null);
      load();
    } catch { toast.error('Failed to save'); }
  };

  const filters = [
    { key: 'all', label: 'All' }, { key: 'Pending', label: 'Pending' },
    { key: 'Approved', label: 'Approved' }, { key: 'Completed', label: 'Completed' },
    { key: 'Cancelled', label: 'Cancelled' },
  ];

  const shown = filter === 'all' ? appointments : appointments.filter(a => a.status === filter);

  if (loading) return <div className="loading-center"><div className="spinner" /></div>;

  return (
    <div className="animate-fade">
      <div style={{ marginBottom: 24 }}>
        <h1 style={{ fontFamily: 'var(--font-display)', fontSize: 28, marginBottom: 6 }}>📅 Appointments</h1>
        <p style={{ color: 'var(--text-muted)' }}>Manage all patient appointments</p>
      </div>

      {/* Filters */}
      <div style={{ display: 'flex', gap: 8, marginBottom: 20, flexWrap: 'wrap' }}>
        {filters.map(f => (
          <button key={f.key} className={`btn btn-sm ${filter === f.key ? 'btn-primary' : 'btn-outline'}`}
            onClick={() => setFilter(f.key)}>
            {f.label}
            <span style={{ marginLeft: 6, background: 'rgba(255,255,255,0.25)', borderRadius: 99, padding: '0 6px', fontSize: 11 }}>
              {f.key === 'all' ? appointments.length : appointments.filter(a => a.status === f.key).length}
            </span>
          </button>
        ))}
      </div>

      <div className="card">
        {shown.length === 0 ? (
          <div className="empty-state">
            <div className="empty-icon">📋</div>
            <h3>No appointments</h3>
          </div>
        ) : (
          <div className="table-wrap">
            <table>
              <thead>
                <tr>
                  <th>Patient</th><th>Date</th><th>Time</th><th>Reason</th>
                  <th>Status</th><th>Actions</th>
                </tr>
              </thead>
              <tbody>
                {shown.map(a => (
                  <tr key={a.id}>
                    <td><strong>{a.patient_name}</strong></td>
                    <td>{new Date(a.appointment_date).toLocaleDateString('en-IN', { day: 'numeric', month: 'short', year: 'numeric' })}</td>
                    <td>{a.appointment_time?.slice(0, 5)}</td>
                    <td style={{ maxWidth: 160, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
                      {a.reason || '—'}
                    </td>
                    <td><span className={`badge ${STATUS_BADGE[a.status]}`}>{a.status}</span></td>
                    <td>
                      <div style={{ display: 'flex', gap: 6 }}>
                        {a.status === 'Pending' && <>
                          <button className="btn btn-primary btn-sm" onClick={() => handleStatus(a.id, 'Approved')}>✅ Approve</button>
                          <button className="btn btn-danger btn-sm" onClick={() => handleStatus(a.id, 'Cancelled')}>✕</button>
                        </>}
                        {a.status === 'Approved' && <>
                          <button className="btn btn-outline btn-sm" onClick={() => openTreatment(a)}>📝 Complete</button>
                          <button className="btn btn-danger btn-sm" onClick={() => handleStatus(a.id, 'Cancelled')}>✕</button>
                        </>}
                        {a.status === 'Completed' && (
                          <button className="btn btn-outline btn-sm" onClick={() => openTreatment(a)}>👁️ View</button>
                        )}
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>

      {/* Treatment Modal */}
      {treatmentModal && (
        <div className="modal-overlay" onClick={() => setTreatmentModal(null)}>
          <div className="modal animate-slide" onClick={e => e.stopPropagation()}>
            <div className="modal-header">
              <h3>Treatment Details – {treatmentModal.patient_name}</h3>
              <button className="modal-close" onClick={() => setTreatmentModal(null)}>×</button>
            </div>
            <div className="modal-body">
              <div style={{ padding: '10px 14px', background: 'var(--bg)', borderRadius: 8, marginBottom: 16, fontSize: 13 }}>
                📅 {new Date(treatmentModal.appointment_date).toLocaleDateString()} · {treatmentModal.appointment_time?.slice(0,5)}
                {treatmentModal.reason && <div style={{ marginTop: 4 }}>📝 Reason: {treatmentModal.reason}</div>}
              </div>
              <div className="form-group">
                <label className="form-label">Treatment Details *</label>
                <textarea className="form-control" rows={4}
                  placeholder="Diagnosis, prescribed treatment, follow-up instructions..."
                  value={treatmentText} onChange={e => setTreatmentText(e.target.value)} />
              </div>
              <div className="form-group">
                <label className="form-label">Doctor's Notes</label>
                <textarea className="form-control" rows={2}
                  placeholder="Additional notes..."
                  value={notes} onChange={e => setNotes(e.target.value)} />
              </div>
            </div>
            <div className="modal-footer">
              <button className="btn btn-outline" onClick={() => setTreatmentModal(null)}>Cancel</button>
              <button className="btn btn-primary" onClick={saveTreatment} disabled={!treatmentText}>
                ✅ Save & Complete
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
